// In InstCombine::visitICmpInst
if (auto *LHS = dyn_cast<BinaryOperator>(I.getOperand(0))) {
  if (LHS->getOpcode() == Instruction::LShr) {
    Value *X = LHS->getOperand(0);
    if (auto *C = dyn_cast<ConstantInt>(LHS->getOperand(1))) {
      unsigned ShiftAmt = C->getZExtValue();
      unsigned BitWidth = X->getType()->getScalarSizeInBits();
      if (ShiftAmt > 0 && ShiftAmt < BitWidth) {
        if (I.getOperand(1) == X) { // Compare with original
          switch (I.getPredicate()) {
            case CmpInst::ICMP_EQ:
              return Builder.CreateICmpEQ(X, Constant::getNullValue(X->getType()));
            case CmpInst::ICMP_NE:
              return Builder.CreateICmpNE(X, Constant::getNullValue(X->getType()));
            // ... handle other predicates
          }
        }
      }
    }
  }
}

